1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
3	const CURSED_SURCHARGE_PERCENT = 50;
4	
5	const BASE_PREMIUMS: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	
14	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
15	const BLOCK_SIZE = 3;
16	const BLOCK_PRICE = 60;
17	
18	const itemBasePremium = (item: any): number => BASE_PREMIUMS[item.type];
19	
20	const sumItemPremiums = (items: any[]): number =>
21	  items.reduce((sum, item) => sum + itemBasePremium(item), 0);
22	
23	const groupByType = (items: any[]): Record<string, any[]> =>
24	  items.reduce((groups, item) => {
25	    (groups[item.type] ||= []).push(item);
26	    return groups;
27	  }, {} as Record<string, any[]>);
28	
29	const isCompleteBlock = (type: string, group: any[]): boolean =>
30	  COMPONENT_TYPES.has(type) && group.length === BLOCK_SIZE;
31	
32	const groupPremium = (type: string, group: any[]): number =>
33	  isCompleteBlock(type, group) ? BLOCK_PRICE : sumItemPremiums(group);
34	
35	const calculateBasePremium = (items: any[]): number =>
36	  Object.entries(groupByType(items)).reduce(
37	    (total, [type, group]) => total + groupPremium(type, group),
38	    0
39	  );
40	
41	const percentOf = (amount: number, percent: number): number =>
42	  (amount * percent) / 100;
43	
44	const addPercent = (amount: number, percent: number): number =>
45	  amount + percentOf(amount, percent);
46	
47	const itemSurcharge = (item: any): number =>
48	  item.cursed ? percentOf(itemBasePremium(item), CURSED_SURCHARGE_PERCENT) : 0;
49	
50	const calculateItemSurcharges = (items: any[]): number =>
51	  items.reduce((sum, item) => sum + itemSurcharge(item), 0);
52	
53	const quotePremium = (items: any[]): number => {
54	  const policyBase = calculateBasePremium(items);
55	  const surcharges = calculateItemSurcharges(items);
56	  const withFirstInsurance = addPercent(policyBase, FIRST_INSURANCE_SURCHARGE_PERCENT);
57	  return Math.ceil(withFirstInsurance + surcharges + PROCESSING_FEE);
58	};
59	
60	export const runScenario = (scenario: any): unknown => {
61	  const items = scenario.steps[0].items;
62	  return { results: [{ premium: quotePremium(items) }] };
63	};
